# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

public int PlayerHealth = 10;
public int PlayerMoney = 0;

public static int BaseAttack = 3;
public static int BaseDefense = 2;
public static int BaseHealth = 5;
public static int MinHealth = 1;
public static int MaxHealth = 10;
public static int HealthModifier = 0;
public static int DamageMultiplier = 2;


public int PlayerAttack; // set by BaseAttack
public int PlayerDefense; // set by BaseDefense and HealthModifier
public int PlayerMoney; // set by the in-app purchase system

// Use this for initialization
void Start () {
    PlayerAttack = BaseAttack + DamageMultiplier * PlayerMoney;  // Set PlayerAttack value
    PlayerDefense = BaseDefense + (HealthModifier / MaxHealth) * (MaxHealth - MinHealth);  //Set PlayerDefense value
    PlayerHealth += HealthModifier;	//Add Player health modifier
    PlayerMoney -= 20;	// Subtract 20 from the player money
}

// Update is called once per frame
void Update () {

	Debug.Log(PlayerAttack);    // Log player attack to console
	Debug.Log(PlayerDefense);   // Log player defense to console
	Debug.Log(PlayerHealth);	  // Log player health to console
}

